definition.script:
pipeline {
    // ---- agent: 在 Jenkins Master 上运行（共享 docker.sock） ----
    agent any

    // ---- 环境变量（编译时可用）----
    environment {
        HARBOR_REGISTRY = '192.168.1.61'      // ← 替换为你的 Harbor 地址
        IMAGE_NAME      = "${HARBOR_REGISTRY}/monitoring/snownlp-demo"
        // 镜像 Tag 格式: 日期-时间-构建号，例如 20260625-101050-2
        IMAGE_TAG       = "${new Date().format('yyyyMMdd-HHmmss')}-${BUILD_NUMBER}"
        DEPLOY_FILE     = '01-app/deployment.yaml'  // ← K8s Deployment YAML 路径
    }

    stages {

        // ============================================================
        // Stage 1: 拉取代码
        // ============================================================
        stage('Checkout') {
            steps {
                echo "=== Stage 1: Checkout ==="
                // 从内网 Git Server 拉取源码（git:// 协议，9418 端口）
                git branch: 'main',
                    url: 'git://git-server.git.svc.cluster.local:9418/snownlp-observability-demo.git'
            }
        }

        // ============================================================
        // Stage 2: 构建 Docker 镜像
        // ============================================================
        stage('Build Image') {
            steps {
                echo "=== Stage 2: Build ==="
                dir('01-app') {
                    // ★关键★ 内网适配: 把 Docker Hub 基础镜像替换为内网 Harbor
                    // 原始 Dockerfile 中 FROM python:3.9-slim → 内网无法拉取
                    // TODO: 如果 Dockerfile 中的基础镜像版本变了，这里也要同步修改
                    sh "sed -i 's|FROM python:3.9-slim|FROM 192.168.1.61/library/python:3.11-slim|' Dockerfile"

                    // 构建镜像（打好 latest 和带时间戳的两个 tag）
                    sh """
                        docker build \
                            -t ${IMAGE_NAME}:${IMAGE_TAG} \
                            -t ${IMAGE_NAME}:latest \
                            --label "build.number=${BUILD_NUMBER}" \
                            --label "build.time=${IMAGE_TAG}" \
                            .
                    """
                }
            }
        }

        // ============================================================
        // Stage 3: 推送镜像到 Harbor
        // ============================================================
        stage('Push Image') {
            steps {
                echo "=== Stage 3: Push to Harbor ==="
                sh "docker push ${IMAGE_NAME}:${IMAGE_TAG}"
                sh "docker push ${IMAGE_NAME}:latest"
            }
        }

        // ============================================================
        // Stage 4: 更新 GitOps 部署清单
        // ============================================================
        // ★核心 GitOps 思想★
        // 不是直接 kubectl set image（会被 ArgoCD 回滚），
        // 而是修改 Git 仓库中的 deployment.yaml，然后 git push
        // ArgoCD 检测到 Git 变更后自动同步到 K8s
        stage('Update GitOps Manifests') {
            steps {
                echo "=== Stage 4: Update deployment.yaml ==="
                sh """
                    sed -i "s|image: ${IMAGE_NAME}:.*|image: ${IMAGE_NAME}:${IMAGE_TAG}|g" ${DEPLOY_FILE}
                    grep 'image:' ${DEPLOY_FILE} | head -3
                """
            }
        }

        // ============================================================
        // Stage 5: Git 提交 & Push
        // ============================================================
        stage('Git Commit & Push') {
            steps {
                echo "=== Stage 5: Git push ==="
                sh """
                    git config user.email "jenkins@cicd.local"
                    git config user.name "Jenkins CI"
                    git add ${DEPLOY_FILE}
                    git diff --cached --stat
                    git commit -m "[CI] auto: update image to ${IMAGE_TAG}

                    Build: #${BUILD_NUMBER}
                    Image: ${IMAGE_NAME}:${IMAGE_TAG}"
                    git push origin HEAD:main
                """
            }
        }

        // ============================================================
        // Stage 6: 等待 ArgoCD 自动同步
        // ============================================================
        // 不需要主动操作 K8s，ArgoCD 每 3 分钟自动检测 Git 变更并同步
        stage('Wait ArgoCD Sync') {
            steps {
                echo "=== Stage 6: ArgoCD will auto-sync within 3min ==="
                echo "  Verify: kubectl -n monitoring get deploy snownlp-demo"
            }
        }
    }

    // ---- 构建后处理 ----
    post {
        success {
            echo "SUCCESS: ${IMAGE_NAME}:${IMAGE_TAG}"
        }
        failure {
            echo "FAILED: Build #${BUILD_NUMBER}"
        }
    }
}
